('business:5-1-role-of-finance-function:match:dca15cf8', 'business', 'business:5-1-role-of-finance-function', '5.1 Role of Finance Function', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Financial Information”?", "options": ["Data including profit, loss, cash flow, break-even, profit margin and average rate of return, used in business decision-making.", "The way different departments within a business rely on each other to function effectively.", "An estimate or prediction of what is expected to happen in the future.", "A measure of how profitable an investment is, calculated as the average annual profit as a percentage of the amount invested."]}'::jsonb, '{"answer": 0, "explain": "“Financial Information” means: Data including profit, loss, cash flow, break-even, profit margin and average rate of return, used in business decision-making."}'::jsonb),
